@* Displays a single task card with move buttons *@

<div class="task-card">
    <h4 class="task-title">@Task.Title</h4>
    <p class="task-assignee">@Task.Assignee</p>
    <span class="priority-badge priority-@Task.Priority.ToLowerInvariant()">@Task.Priority</span>
    <span class="task-due-date">@Task.DueDate.ToString("MMM dd")</span>

    <div class="task-actions">
        @if (ShowMoveLeft)
        {
            <button class="btn-move-left" @onclick="OnMoveLeftClicked">Move Left</button>
        }
        @if (ShowMoveRight)
        {
            <button class="btn-move-right" @onclick="OnMoveRightClicked">Move Right</button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public TaskItem Task { get; set; } = default!;

    [Parameter]
    public bool ShowMoveLeft { get; set; }

    [Parameter]
    public bool ShowMoveRight { get; set; }

    [Parameter]
    public EventCallback OnMoveLeft { get; set; }

    [Parameter]
    public EventCallback OnMoveRight { get; set; }

    private async System.Threading.Tasks.Task OnMoveLeftClicked() => await OnMoveLeft.InvokeAsync();
    private async System.Threading.Tasks.Task OnMoveRightClicked() => await OnMoveRight.InvokeAsync();
}

@* Inline form to add a new task within a column *@

<div class="add-task-form">
    <div class="form-field">
        <label>Title</label>
        <input type="text" @bind="title" placeholder="Task title" />
    </div>
    <div class="form-field">
        <label>Assignee</label>
        <input type="text" @bind="assignee" placeholder="Assignee name" />
    </div>
    <div class="form-field">
        <label>Priority</label>
        <select @bind="priority">
            <option value="High">High</option>
            <option value="Medium">Medium</option>
            <option value="Low">Low</option>
        </select>
    </div>
    <div class="form-field">
        <label>Due Date</label>
        <input type="date" @bind="dueDate" />
    </div>
    <div class="form-actions">
        <button class="btn-save" @onclick="Save">Save</button>
        <button class="btn-cancel" @onclick="Cancel">Cancel</button>
    </div>
</div>

@code {
    [Parameter]
    public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnSave { get; set; }

    [Parameter]
    public EventCallback OnCancel { get; set; }

    private string title = string.Empty;
    private string assignee = string.Empty;
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today;

    private async Task Save()
    {
        if (!string.IsNullOrWhiteSpace(title))
        {
            await OnSave.InvokeAsync((title, assignee, priority, dueDate));
            title = string.Empty;
            assignee = string.Empty;
            priority = "Medium";
            dueDate = DateTime.Today;
        }
    }

    private async Task Cancel()
    {
        await OnCancel.InvokeAsync();
    }
}

@* A single Kanban column displaying tasks and an add form *@

<div class="kanban-column">
    <div class="column-header">
        <h3>@Title (@Tasks.Count)</h3>
    </div>

    <div class="column-body">
        @foreach (var task in Tasks)
        {
            <TaskCard Task="task"
                      ShowMoveLeft="ShowMoveLeft"
                      ShowMoveRight="ShowMoveRight"
                      OnMoveLeft="@(() => MoveLeft(task))"
                      OnMoveRight="@(() => MoveRight(task))" />
        }
    </div>

    <div class="column-footer">
        @if (showForm)
        {
            <AddTaskForm OnSave="HandleSave" OnCancel="HideForm" />
        }
        else
        {
            <button class="btn-add-task" @onclick="ShowForm">Add Task</button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public string Title { get; set; } = string.Empty;

    [Parameter, EditorRequired]
    public List<TaskItem> Tasks { get; set; } = new();

    [Parameter]
    public bool ShowMoveLeft { get; set; }

    [Parameter]
    public bool ShowMoveRight { get; set; }

    [Parameter]
    public EventCallback<TaskItem> OnMoveLeft { get; set; }

    [Parameter]
    public EventCallback<TaskItem> OnMoveRight { get; set; }

    [Parameter]
    public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnTaskCreated { get; set; }

    private bool showForm;

    private void ShowForm() => showForm = true;
    private void HideForm() => showForm = false;

    private async Task MoveLeft(TaskItem task) => await OnMoveLeft.InvokeAsync(task);
    private async Task MoveRight(TaskItem task) => await OnMoveRight.InvokeAsync(task);

    private async Task HandleSave((string Title, string Assignee, string Priority, DateTime DueDate) data)
    {
        await OnTaskCreated.InvokeAsync(data);
        showForm = false;
    }
}

@* Search bar for filtering tasks by title *@

<div class="board-search-bar">
    <input type="text"
           placeholder="Search tasks by title..."
           value="@SearchText"
           @oninput="OnInput" />
</div>

@code {
    [Parameter]
    public string SearchText { get; set; } = string.Empty;

    [Parameter]
    public EventCallback<string> SearchTextChanged { get; set; }

    private async Task OnInput(ChangeEventArgs e)
    {
        var value = e.Value?.ToString() ?? string.Empty;
        await SearchTextChanged.InvokeAsync(value);
    }
}

@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h2>Project Board</h2>

@if (isLoading)
{
    <p class="loading-message">Loading tasks...</p>
}
else if (errorMessage is not null)
{
    <p class="error-message">@errorMessage</p>
}
else
{
    <BoardStatsBar Tasks="allTasks" />
    <BoardSearchBar SearchText="@searchText" SearchTextChanged="OnSearchChanged" />

    <div class="kanban-board">
        <KanbanColumn Title="To Do"
                      Tasks="GetFilteredTasks("To Do")"
                      ShowMoveLeft="false"
                      ShowMoveRight="true"
                      OnMoveRight="@(task => MoveTask(task, "In Progress"))"
                      OnTaskCreated="@(data => CreateTask(data, "To Do"))" />

        <KanbanColumn Title="In Progress"
                      Tasks="GetFilteredTasks("In Progress")"
                      ShowMoveLeft="true"
                      ShowMoveRight="true"
                      OnMoveLeft="@(task => MoveTask(task, "To Do"))"
                      OnMoveRight="@(task => MoveTask(task, "Done"))"
                      OnTaskCreated="@(data => CreateTask(data, "In Progress"))" />

        <KanbanColumn Title="Done"
                      Tasks="GetFilteredTasks("Done")"
                      ShowMoveLeft="true"
                      ShowMoveRight="false"
                      OnMoveLeft="@(task => MoveTask(task, "In Progress"))"
                      OnTaskCreated="@(data => CreateTask(data, "Done"))" />
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchText = string.Empty;
    private bool isLoading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private List<TaskItem> GetFilteredTasks(string status)
    {
        var filtered = allTasks.Where(t => t.Status == status);

        if (!string.IsNullOrWhiteSpace(searchText))
        {
            filtered = filtered.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
        }

        return filtered.ToList();
    }

    private void OnSearchChanged(string value)
    {
        searchText = value;
    }

    private async Task MoveTask(TaskItem task, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            var index = allTasks.FindIndex(t => t.Id == task.Id);
            if (index >= 0)
            {
                allTasks[index] = task with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private async Task CreateTask((string Title, string Assignee, string Priority, DateTime DueDate) data, string status)
    {
        try
        {
            var newTask = await TaskService.CreateTaskAsync(data.Title, data.Assignee, data.Priority, data.DueDate);
            // The service returns the task; ensure it has the correct status
            allTasks.Add(newTask with { Status = status });
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create task: {ex.Message}";
        }
    }
}

